import React, { useEffect, useState } from 'react';
import { useSearchParams } from 'react-router-dom';
import axios from 'axios';
import { useCart } from '../context/CartContext';
import ProductCard from '../components/ProductCard';

const Products = () => {
  const [searchParams] = useSearchParams();
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [fetchError, setFetchError] = useState(null);
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [sortBy, setSortBy] = useState('featured');
  const { addToCart } = useCart();

  useEffect(() => {
    const category = searchParams.get('cat') || 'all';
    setSelectedCategory(category);
    fetchProducts(category);
  }, [searchParams]);

  const fetchProducts = async (category = 'all') => {
    setLoading(true);
    try {
      const url = category === 'all' 
        ? '/api/products' 
        : `/api/products?category=${category}`;
      const response = await axios.get(url);
      setProducts(response.data);
    } catch (error) {
      console.error('Error fetching products:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleCategoryChange = (category) => {
    setSelectedCategory(category);
    fetchProducts(category);
  };

  const handleSortChange = (sort) => {
    setSortBy(sort);
    // Products will be sorted in render
  };

  const handleAddToCart = async (product) => {
    const result = await addToCart(product);
    if (result.success) {
      alert(`✓ "${product.name}" added to cart`);
    } else {
      alert(result.error || 'Failed to add to cart');
    }
  };

  const sortedProducts = [...products].sort((a, b) => {
    switch (sortBy) {
      case 'price-asc':
        return a.price - b.price;
      case 'price-desc':
        return b.price - a.price;
      case 'name':
        return a.name.localeCompare(b.name);
      default:
        return 0;
    }
  });

  return (
    <>
      <header className="page-header">
        <div className="container">
          <h1>Shop All Products</h1>
          <ol className="breadcrumb" aria-label="Breadcrumb">
            <li><a href="/">Home</a></li>
            <li className="active">Shop</li>
          </ol>
        </div>
      </header>

      <main className="section" id="main-content">
        <div className="container">
          <div className="categories-strip" role="group" style={{ marginBottom: '2rem' }}>
            {['all', 'electronics', 'fashion', 'home', 'beauty', 'sports'].map(cat => (
              <button
                key={cat}
                className={`category-chip ${selectedCategory === cat ? 'active' : ''}`}
                onClick={() => handleCategoryChange(cat)}
              >
                {cat === 'all' ? 'All Products' : 
                 cat === 'electronics' ? '📱 Electronics' :
                 cat === 'fashion' ? '👗 Fashion' :
                 cat === 'home' ? '🏡 Home' :
                 cat === 'beauty' ? '💄 Beauty' : '⚽ Sports'}
              </button>
            ))}
          </div>

          <div className="shop-toolbar">
            <p className="results-count">Showing {products.length} products</p>
            <div className="toolbar-right">
              <select 
                className="sort-select" 
                value={sortBy}
                onChange={(e) => handleSortChange(e.target.value)}
              >
                <option value="featured">Featured</option>
                <option value="price-asc">Price: Low to High</option>
                <option value="price-desc">Price: High to Low</option>
                <option value="name">Name A–Z</option>
              </select>
            </div>
          </div>

          {loading ? (
            <div style={{ textAlign: 'center', padding: '4rem' }}>
              <p>Loading products...</p>
            </div>
          ) : (
            <div className="products-grid" role="list">
              {sortedProducts.map(product => (
                <ProductCard 
                  key={product._id} 
                  product={product} 
                  onAddToCart={handleAddToCart}
                />
              ))}
            </div>
          )}
        </div>
      </main>
    </>
  );
};

export default Products;
